import os, sys, json, argparse, math
from collections import deque
from cogniplan_env import ExplorationEnv

class Planner:
    def __init__(self, alpha=0.7, alpha_slope=1.0, vp=0.5, nuw=0.8):
        self.alpha = alpha
        self.alpha_slope = alpha_slope
        self.vp = vp
        self.nuw = nuw
        self.visited = set()

    def reset(self):
        self.visited = set()

    def _key(self, c):
        return (round(c[0], 1), round(c[1], 1))

    def select(self, obs):
        nodes = obs['nodes']
        neighbors = obs['neighbors']
        rp = obs['robot_pos']
        er = obs['explored_rate']
        self.visited.add(self._key(rp))
        if not neighbors:
            return None
        util = {}
        adj = {}
        for n in nodes:
            k = self._key(n['coords'])
            util[k] = float(n['utility'])
            adj[k] = [self._key(x) for x in n.get('neighbors', [])]
        aug = {}
        for k in adj:
            u = util.get(k, 0)
            for nk in adj[k]:
                u += self.nuw * util.get(nk, 0)
            aug[k] = u
        dist = {}
        queue = deque()
        for nb in neighbors:
            nk = self._key(nb)
            if nk not in dist:
                dist[nk] = (1, nk)
                queue.append(nk)
        while queue:
            cur = queue.popleft()
            cd, fs = dist[cur]
            for nk in adj.get(cur, []):
                if nk not in dist:
                    dist[nk] = (cd + 1, fs)
                    queue.append(nk)
        ea = self.alpha + self.alpha_slope * er

        def find_best(vp_val):
            bs, bfs = -1e18, None
            for nk, (d, fs) in dist.items():
                u = aug.get(nk, 0)
                if vp_val > 0 and nk in self.visited:
                    u *= (1.0 - vp_val)
                if u <= 0:
                    continue
                s = u / (d ** ea)
                if s > bs:
                    bs, bfs = s, fs
            return bfs

        best_fs = find_best(self.vp)
        if best_fs is None:
            best_fs = find_best(0.0)
        if best_fs is not None:
            for nb in neighbors:
                if self._key(nb) == best_fs:
                    return nb
        for nb in neighbors:
            if self._key(nb) not in self.visited:
                return nb
        return neighbors[0]


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for _ in range(128):
        t = planner.select(obs)
        if t is None:
            break
        obs, info = env.step(t)
        if info.get('done', False):
            break
    return env.get_metrics()


def main():
    pa = argparse.ArgumentParser()
    pa.add_argument('--data_path', required=True)
    pa.add_argument('--checkpoint', required=True)
    pa.add_argument('--output', required=True)
    args = pa.parse_args()
    cfg = {}
    cp = os.path.join(args.checkpoint, 'config.json')
    if os.path.exists(cp):
        with open(cp) as f:
            cfg = json.load(f)
    planner = Planner(
        alpha=cfg.get('alpha', 0.7),
        alpha_slope=cfg.get('alpha_slope', 1.0),
        vp=cfg.get('visited_penalty', 0.5),
        nuw=cfg.get('neighbor_util_weight', 0.8),
    )
    md = os.path.join(args.data_path, 'maps_eval')
    eps = []
    for et in ['room', 'tunnel', 'outdoor']:
        td = os.path.join(md, et)
        if not os.path.isdir(td):
            continue
        for fn in sorted(os.listdir(td)):
            if fn.endswith('.png'):
                eps.append({'mp': os.path.join(et, fn), 'et': et, 'fp': os.path.join(td, fn)})
    pe = []
    for ep in eps:
        env = ExplorationEnv(map_path=ep['fp'])
        m = run_episode(env, planner)
        pe.append({'map_path': ep['mp'], 'env_type': ep['et'],
                    'success': 1 if m['success'] else 0,
                    'travel_distance': m['travel_distance'],
                    'explored_rate': m['explored_rate']})
    n = len(pe)
    er = sum(r['explored_rate'] for r in pe) / n if n else 0
    sr = sum(r['success'] for r in pe) / n if n else 0
    sd = [r['travel_distance'] for r in pe if r['success'] == 1]
    td = sum(sd) / len(sd) if sd else 0.0
    pt = {}
    for t in ['room', 'tunnel', 'outdoor']:
        rs = [r for r in pe if r['env_type'] == t]
        nt = len(rs)
        if nt == 0:
            continue
        sc = sum(r['success'] for r in rs)
        pt[t] = {'explored_rate': sum(r['explored_rate'] for r in rs) / nt,
                  'travel_distance': sum(r['travel_distance'] for r in rs if r['success'] == 1) / max(1, sc),
                  'success_rate': sc / nt}
    out = {'explored_rate': er, 'travel_distance': td, 'success_rate': sr,
           'per_episode': pe, 'per_type': pt, 'total_episodes': n}
    with open(args.output, 'w') as f:
        json.dump(out, f, indent=2)


if __name__ == '__main__':
    main()
